import { useQuery, useAction } from '@wasp/actions'
import getTasks from '@src/queries'
import createTask from '@src/actions'
import togglePriority from '@src/actions'
import { useState } from 'react'
import './Main.css'

export function MainPage() {
  const { data: tasks, isLoading, error } = useQuery(getTasks)
  const createTaskFn = useAction(createTask)
  const togglePriorityFn = useAction(togglePriority)

  const [newTaskDescription, setNewTaskDescription] = useState('')

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!newTaskDescription.trim()) return

    try {
      await createTaskFn({ description: newTaskDescription })
      setNewTaskDescription('')
    } catch (err) {
      console.error('Failed to create task:', err)
    }
  }

  const handleTogglePriority = async (id: string) => {
    try {
      await togglePriorityFn({ id })
    } catch (err) {
      console.error('Failed to toggle priority:', err)
    }
  }

  if (isLoading) {
    return (
      <main className="container">
        <h1 className="title">Task Priority List</h1>
        <p>Loading tasks...</p>
      </main>
    )
  }

  if (error) {
    return (
      <main className="container">
        <h1 className="title">Task Priority List</h1>
        <p className="error">Error loading tasks: {error.message}</p>
      </main>
    )
  }

  return (
    <main className="container">
      <h1 className="title">Task Priority List</h1>

      <form onSubmit={handleSubmit} className="task-form">
        <input
          type="text"
          value={newTaskDescription}
          onChange={(e) => setNewTaskDescription(e.target.value)}
          placeholder="Enter task description..."
          className="task-input"
        />
        <button type="submit" className="button button-filled">
          Add Task
        </button>
      </form>

      <div className="task-list">
        {tasks && tasks.length > 0 ? (
          tasks.map((task) => (
            <div key={task.id} className="task-item">
              <span className="task-description">{task.description}</span>
              <div className="task-actions">
                <span
                  className={`priority-badge priority-${task.priority.toLowerCase()}`}
                >
                  {task.priority}
                </span>
                <button
                  onClick={() => handleTogglePriority(task.id)}
                  className="button button-outlined"
                >
                  Toggle Priority
                </button>
              </div>
            </div>
          ))
        ) : (
          <p className="empty-state">No tasks yet. Add one above!</p>
        )}
      </div>
    </main>
  )
}

