    config(config) {
      return mergeConfig({
        base: "/",
        optimizeDeps: {
          exclude: ['wasp', '@wasp.sh/lib-auth']
        },
        server: {
          port: 3000,
          host: "0.0.0.0",
          open: true,
        },
        envPrefix: "REACT_APP_",
        build: {
          outDir: ".wasp/out/web-app/build/",
